import { useEffect, useMemo, useRef, useState } from "react";
import { useSession, useUser } from "@clerk/clerk-react";
import { AnimatePresence, motion } from "framer-motion";
import {
  AlertCircle, ArrowRight, BookOpen, Building2, CalendarDays, CheckCircle2, ChevronDown,
  CircleDollarSign, ClipboardCheck, Download, FileCheck2, FileText, Filter, GraduationCap,
  LayoutDashboard, Loader2, Menu, Plus, RefreshCcw, Save, Search, Send, Settings2,
  ShieldCheck, Star, Trash2, UploadCloud, UserRound, Users, X,
} from "lucide-react";
import { PortalSignOutButton } from "../components/AuthStatus";
import PortalSetupNotice from "../components/PortalSetupNotice";
import { isSupabaseConfigured } from "../lib/env";
import { createPortalSupabaseClient } from "../lib/supabaseClient";
import logo from "../logo.png";

const BRAND = { burgundy: "#721100", gold: "#dd7d00", ink: "#24130e", cream: "#f7f3ef" };
const INPUT = "w-full rounded-2xl border border-slate-200 bg-white px-4 py-3 text-sm text-slate-800 outline-none transition focus:border-[#dd7d00] focus:ring-4 focus:ring-[#dd7d00]/10";
const CLIENT_DOCS = [["service_agreement","Service agreement"],["purchase_order","Purchase order"],["tax_exempt","Tax-exempt certificate"],["accessibility_plan","Accessibility plan"],["prep_materials","Preparation materials"],["other","Other document"]];
const INTERPRETER_DOCS = [["resume","Résumé"],["w9","W-9"],["credential_proof","Credential proof"],["liability_insurance","Liability insurance"],["ic_agreement","IC agreement"],["state_license","State license"],["work_sample","Work sample"]];
const CREDENTIAL_OPTIONS = ["National Interpreter Certification (NIC)","Certified Deaf Interpreter (CDI)","Board for Evaluation of Interpreters (BEI)","Educational Interpreter Performance Assessment (EIPA)","Uncertified","Other"];
const MODALITY_OPTIONS = ["ASL (American Sign Language)","PTASL (Pro-Tactile ASL)","CASE (Conceptually Accurate Signed English)","Trilingual (ASL, English, Spanish)","MCE (Manually Coded English)","Cued Speech","Other"];
const SETTING_OPTIONS = ["Medical","Legal","Edu.(K-12)","Edu.(Post-Secondary)","Mental Health","Community / Freelance","Platform / Conference","Performance / Arts","Cruise","Video Relay Service (VRS)","Video Remote Interpreting (VRI)","English > ASL Translation","ASL > English Translation"];
const EXPERIENCE_OPTIONS = ["Less than 1 year","1-3 years","4-6 years","7-10 years","10+ years"];
const EMPTY_CLIENT = { organization_name:"", primary_contact_name:"", phone:"", preferred_contact_method:"Email", billing_email:"", billing_phone:"", address_line_1:"", address_line_2:"", city:"", state:"", postal_code:"", country:"United States", industry:"", default_service_type:"ASL/English Interpreting", default_delivery_mode:"On-site", communication_preferences:"", billing_notes:"" };
const EMPTY_INTERPRETER = { first_name:"", last_name:"", email:"", phone:"", current_location:"", preferred_contact_method:"Email", credentials:"", state_license:"", state_license_details:"", years_experience:"", modalities:"", areas_of_experience:"", assignment_type_preference:"", willing_to_travel:"", technical_readiness_confirmed:"", professional_liability_insurance:"", onsite_rate:"", vri_rate:"", travel_radius:"" };
const EMPTY_ASSIGNMENT = { service_type:"ASL/English Interpreting", delivery_mode:"On-site", start_at:"", end_at:"", timezone:"America/New_York", location_name:"", address_line_1:"", city:"", state:"", postal_code:"", meeting_link:"", deaf_participants:1, hearing_participants:1, language_preferences:"ASL", specialty:"General / Community", team_requested:false, cdi_requested:false, onsite_contact_name:"", onsite_contact_phone:"", description:"", preparation_materials:"", purchase_order_number:"", client_reference:"" };

const join = (...items) => items.filter(Boolean).join(" ");
const pretty = (value) => String(value || "Not set").replaceAll("_", " ").replace(/\b\w/g, (x) => x.toUpperCase());
const formatDate = (value) => value ? new Intl.DateTimeFormat("en", { month:"short", day:"numeric", year:"numeric", hour:"numeric", minute:"2-digit" }).format(new Date(value)) : "Not scheduled";
const safe = (value) => String(value || "").trim();
const matches = (value, selected) => !selected.length || selected.every((item) => safe(value).toLowerCase().includes(item.toLowerCase()));

function Field({ name, children, required, className="" }) { return <label className={className}><span className="mb-2 block text-xs font-black uppercase tracking-[.1em] text-slate-500">{name}{required && <b className="text-[#721100]"> *</b>}</span>{children}</label>; }
function SectionTitle({ eyebrow, title, text, action }) { return <div className="flex flex-col gap-4 md:flex-row md:items-end md:justify-between"><div><p className="text-xs font-black uppercase tracking-[.16em] text-[#dd7d00]">{eyebrow}</p><h2 className="mt-2 text-2xl font-black text-slate-900 md:text-3xl">{title}</h2>{text && <p className="mt-2 max-w-3xl text-sm leading-6 text-slate-500">{text}</p>}</div>{action}</div>; }
function Badge({ value }) { const style = ({ pending_confirmation:"bg-amber-50 text-amber-800 border-amber-200", confirmed:"bg-emerald-50 text-emerald-800 border-emerald-200", completed:"bg-slate-100 text-slate-700 border-slate-200", cancelled:"bg-rose-50 text-rose-800 border-rose-200", pending_payment:"bg-orange-50 text-orange-800 border-orange-200", paid:"bg-emerald-50 text-emerald-800 border-emerald-200", open:"bg-emerald-50 text-emerald-800 border-emerald-200", submitted:"bg-blue-50 text-blue-800 border-blue-200", accepted:"bg-emerald-50 text-emerald-800 border-emerald-200", declined:"bg-rose-50 text-rose-800 border-rose-200", completed_training:"bg-emerald-50 text-emerald-800 border-emerald-200" })[value] || "bg-slate-50 text-slate-600 border-slate-200"; return <span className={join("inline-flex rounded-full border px-2.5 py-1 text-[10px] font-black uppercase tracking-[.08em]",style)}>{pretty(value)}</span>; }
function Card({ children, className="" }) { return <motion.div layout initial={{opacity:0,y:8}} animate={{opacity:1,y:0}} className={join("rounded-[1.8rem] border border-black/5 bg-white p-5 shadow-[0_18px_55px_rgba(40,25,18,.07)] md:p-6",className)}>{children}</motion.div>; }
function Metric({ icon:Icon, name, value, note, color=BRAND.burgundy }) { return <motion.div whileHover={{y:-3}} className="rounded-[1.6rem] border border-black/5 bg-white p-5 shadow-[0_16px_50px_rgba(40,25,18,.07)]"><div className="flex justify-between gap-4"><div><p className="text-xs font-black uppercase tracking-[.14em] text-slate-400">{name}</p><p className="mt-3 text-3xl font-black text-slate-900">{value}</p><p className="mt-2 text-xs leading-5 text-slate-500">{note}</p></div><span className="flex h-11 w-11 items-center justify-center rounded-2xl text-white" style={{background:color}}><Icon size={20}/></span></div></motion.div>; }
function Empty({ icon:Icon=FileText, title, text }) { return <div className="rounded-[1.6rem] border border-dashed border-slate-300 bg-white/60 px-6 py-10 text-center"><span className="mx-auto flex h-12 w-12 items-center justify-center rounded-2xl bg-[#721100]/10 text-[#721100]"><Icon size={22}/></span><h3 className="mt-4 text-lg font-black text-slate-900">{title}</h3><p className="mx-auto mt-2 max-w-lg text-sm leading-6 text-slate-500">{text}</p></div>; }
function Modal({ open, close, title, children, wide=false }) { return <AnimatePresence>{open && <motion.div initial={{opacity:0}} animate={{opacity:1}} exit={{opacity:0}} className="fixed inset-0 z-[100] flex items-center justify-center bg-[#1c100c]/65 p-4 backdrop-blur-sm" onMouseDown={(e)=>e.target===e.currentTarget&&close()}><motion.div initial={{y:22,opacity:0,scale:.98}} animate={{y:0,opacity:1,scale:1}} exit={{y:15,opacity:0}} className={join("max-h-[92vh] w-full overflow-y-auto rounded-[2rem] bg-[#f8f5f1] shadow-2xl",wide?"max-w-5xl":"max-w-3xl")}><div className="sticky top-0 z-10 flex items-center justify-between border-b border-black/5 bg-[#f8f5f1]/95 px-6 py-5 backdrop-blur"><h2 className="text-2xl font-black text-slate-900">{title}</h2><button onClick={close} className="flex h-10 w-10 items-center justify-center rounded-full bg-white text-slate-500 shadow"><X size={18}/></button></div><div className="p-6 md:p-8">{children}</div></motion.div></motion.div>}</AnimatePresence>; }

function DocumentCard({ type, title, document, request, busy, upload, open, remove }) {
  const ref = useRef(null);
  const accept = (file) => file && upload(type,file,document?.id||null);
  return <motion.div layout whileHover={{y:-2}} className="rounded-[1.5rem] border border-slate-200 bg-white p-5 shadow-sm transition hover:border-[#dd7d00]/40 hover:shadow-lg"><div className="flex items-start justify-between gap-3"><div className="flex gap-3"><span className={join("flex h-11 w-11 items-center justify-center rounded-2xl",document?"bg-emerald-50 text-emerald-700":"bg-slate-100 text-slate-500")}>{document?<FileCheck2 size={20}/>:<FileText size={20}/>}</span><div><h3 className="font-black text-slate-900">{request?.title||title}</h3><p className="mt-1 text-xs leading-5 text-slate-500">{request?.instructions||"Upload the latest requested version."}</p></div></div>{request&&<Badge value={request.status}/>}</div>{document&&<div className="mt-4 rounded-2xl bg-slate-50 px-4 py-3"><p className="truncate text-sm font-bold text-slate-700">{document.file_name}</p><p className="mt-1 text-xs text-slate-400">Uploaded {formatDate(document.uploaded_at)}</p></div>}<div className="mt-4 rounded-2xl border border-dashed border-slate-300 bg-slate-50 p-4 text-center" onDragOver={(e)=>e.preventDefault()} onDrop={(e)=>{e.preventDefault();accept(e.dataTransfer.files?.[0]);}}><input ref={ref} type="file" accept=".pdf,.doc,.docx,.png,.jpg,.jpeg" className="hidden" onChange={(e)=>{accept(e.target.files?.[0]);e.target.value="";}}/><button type="button" disabled={busy===type} onClick={()=>ref.current?.click()} className="inline-flex items-center gap-2 text-sm font-black text-[#721100] disabled:opacity-50">{busy===type?<Loader2 className="animate-spin" size={16}/>:<UploadCloud size={16}/>} {document?"Replace file":"Choose or drop a file"}</button><p className="mt-1 text-[11px] text-slate-400">PDF, Word, PNG, or JPG · 15 MB max</p></div>{document&&<div className="mt-4 flex gap-2"><button onClick={()=>open(document)} className="inline-flex items-center gap-2 rounded-xl border border-slate-200 px-3 py-2 text-xs font-black text-slate-600"><Download size={14}/> Open</button><button onClick={()=>remove(document)} className="inline-flex items-center gap-2 rounded-xl bg-rose-50 px-3 py-2 text-xs font-black text-rose-700"><Trash2 size={14}/> Delete</button></div>}</motion.div>;
}

export default function UnifiedPortal({ palette }) {
  const { user, isLoaded } = useUser();
  const { session } = useSession();
  const storage = useMemo(()=>createPortalSupabaseClient(null),[]);
  const [workspace,setWorkspace]=useState(null), [operations,setOperations]=useState(null);
  const [portal,setPortal]=useState("interpreter"), [section,setSection]=useState("overview");
  const [loading,setLoading]=useState(true), [refreshing,setRefreshing]=useState(false), [error,setError]=useState(""), [success,setSuccess]=useState("");
  const [menuOpen,setMenuOpen]=useState(false), [busyDoc,setBusyDoc]=useState(""), [saving,setSaving]=useState(false);
  const [profileOpen,setProfileOpen]=useState(false), [requestOpen,setRequestOpen]=useState(false), [inviteOpen,setInviteOpen]=useState(false), [docRequestOpen,setDocRequestOpen]=useState(false), [courseOpen,setCourseOpen]=useState(false), [opportunityOpen,setOpportunityOpen]=useState(false);
  const [clientDraft,setClientDraft]=useState(EMPTY_CLIENT), [interpreterDraft,setInterpreterDraft]=useState(EMPTY_INTERPRETER), [assignmentDraft,setAssignmentDraft]=useState(EMPTY_ASSIGNMENT);
  const [invite,setInvite]=useState({role:"client",email:"",organizationName:""}), [docRequest,setDocRequest]=useState({audienceType:"client",ownerId:"",documentType:"service_agreement",title:"",instructions:"",dueDate:""});
  const [courseDraft,setCourseDraft]=useState({title:"",description:"",category:"Professional Development",contentUrl:"",durationMinutes:"",isPublished:true,sortOrder:0});
  const [opportunityDraft,setOpportunityDraft]=useState({assignmentId:"",status:"open",closesAt:"",notes:""});
  const [feedbackDraft,setFeedbackDraft]=useState({assignmentId:"",rating:5,comments:"",followUpRequested:false});

  async function apiBase(action,method="GET",body){const t=await session?.getToken();const r=await fetch(`/api/portal?action=${action}`,{method,headers:{authorization:`Bearer ${t}`,...(body?{"content-type":"application/json"}:{})},body:body?JSON.stringify(body):undefined});const d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(d.error||"Portal request failed.");return d;}
  async function apiOps(action,method="GET",body){const t=await session?.getToken();const r=await fetch(`/api/portal-operations?action=${action}`,{method,headers:{authorization:`Bearer ${t}`,...(body?{"content-type":"application/json"}:{})},body:body?JSON.stringify(body):undefined});const d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(d.error||"Portal operation failed.");return d;}
  function flash(message){setSuccess(message);setTimeout(()=>setSuccess(""),3500);}
  async function load(quiet=false){if(!session)return;try{quiet?setRefreshing(true):setLoading(true);setError("");const [w,o]=await Promise.all([apiBase("loadWorkspace"),apiOps("loadOperations")]);setWorkspace(w);setOperations(o);const saved=localStorage.getItem("mls-active-portal");const next=w.availablePortals?.includes(saved)?saved:w.defaultPortal||w.availablePortals?.[0]||"interpreter";setPortal(next);if(w.client?.profile)setClientDraft({...EMPTY_CLIENT,...w.client.profile});if(w.interpreter?.profile)setInterpreterDraft({...EMPTY_INTERPRETER,...w.interpreter.profile});}catch(e){setError(e.message);}finally{setLoading(false);setRefreshing(false);}}
  useEffect(()=>{if(isLoaded&&user&&session&&isSupabaseConfigured)load();},[isLoaded,user?.id,session]);
  useEffect(()=>{setSection("overview");setMenuOpen(false);if(workspace){localStorage.setItem("mls-active-portal",portal);apiBase("savePortalPreference","POST",{defaultPortal:portal}).catch(()=>{});}},[portal]);

  const isAdmin=workspace?.user?.isAdmin;
  const activeClient=workspace?.client;
  const activeInterpreter=workspace?.interpreter;
  async function saveProfile(e){e.preventDefault();setSaving(true);try{if(portal==="client")await apiBase("saveClientProfile","POST",{profile:clientDraft});else await apiBase("saveInterpreterProfile","POST",{profile:interpreterDraft});flash("Profile saved.");setProfileOpen(false);await load(true);}catch(e){setError(e.message);}finally{setSaving(false);}}
  async function createAssignment(e){e.preventDefault();setSaving(true);try{await apiBase("createAssignment","POST",{assignment:assignmentDraft});flash("Interpreter request submitted.");setAssignmentDraft(EMPTY_ASSIGNMENT);setRequestOpen(false);await load(true);}catch(e){setError(e.message);}finally{setSaving(false);}}
  function ownerId(audience){if(!isAdmin)return undefined;return audience==="client"?activeClient?.profile?.id:activeInterpreter?.profile?.id;}
  async function upload(audience,type,file,replaceDocumentId){setBusyDoc(type);try{const signed=await apiBase("createUploadUrl","POST",{audienceType:audience,ownerId:ownerId(audience),documentType:type,fileName:file.name,fileSize:file.size});const result=await storage.storage.from(signed.bucket).uploadToSignedUrl(signed.path,signed.token,file);if(result.error)throw result.error;await apiBase("recordUpload","POST",{audienceType:audience,ownerId:ownerId(audience),documentType:type,fileName:file.name,storagePath:signed.path,replaceDocumentId});flash(replaceDocumentId?"Document replaced.":"Document uploaded.");await load(true);}catch(e){setError(e.message);}finally{setBusyDoc("");}}
  async function openDoc(audience,doc){try{const d=await apiBase("createDocumentOpenLink","POST",{audienceType:audience,ownerId:ownerId(audience),documentId:doc.id});window.open(d.url,"_blank","noopener,noreferrer");}catch(e){setError(e.message);}}
  async function removeDoc(audience,doc){if(!confirm(`Delete ${doc.file_name}?`))return;try{await apiBase("deleteDocument","POST",{audienceType:audience,ownerId:ownerId(audience),documentId:doc.id});flash("Document deleted.");await load(true);}catch(e){setError(e.message);}}
  async function submitFeedback(e){e.preventDefault();setSaving(true);try{await apiOps("submitFeedback","POST",feedbackDraft);flash("Feedback submitted. Thank you.");setFeedbackDraft({assignmentId:"",rating:5,comments:"",followUpRequested:false});await load(true);}catch(e){setError(e.message);}finally{setSaving(false);}}
  async function submitBid(opportunity){const bidRate=prompt("Optional bid rate (leave blank to use your profile rate):","");if(bidRate===null)return;const message=prompt("Optional note to MLS:","")||"";try{await apiOps("submitBid","POST",{opportunityId:opportunity.id,bidRate,message});flash("Bid submitted.");await load(true);}catch(e){setError(e.message);}}
  async function progressCourse(course,percent){try{await apiOps("updateTraining","POST",{courseId:course.id,progressPercent:percent});flash(percent===100?"Course completed.":"Training progress updated.");await load(true);}catch(e){setError(e.message);}}
  async function inviteUser(e){e.preventDefault();setSaving(true);try{await apiBase("invitePortalUser","POST",invite);flash("Portal invitation sent.");setInvite({role:"client",email:"",organizationName:""});setInviteOpen(false);}catch(e){setError(e.message);}finally{setSaving(false);}}
  async function createDocRequest(e){e.preventDefault();setSaving(true);try{await apiBase("adminCreateDocumentRequest","POST",docRequest);flash("Document request created.");setDocRequest({audienceType:"client",ownerId:"",documentType:"service_agreement",title:"",instructions:"",dueDate:""});setDocRequestOpen(false);await load(true);}catch(e){setError(e.message);}finally{setSaving(false);}}
  async function updateAssignment(item,patch){try{await apiBase("adminUpdateAssignment","POST",{assignmentId:item.id,...patch});flash("Assignment updated.");await load(true);}catch(e){setError(e.message);}}
  async function saveCourse(e){e.preventDefault();setSaving(true);try{await apiOps("adminSaveCourse","POST",courseDraft);flash("Training course saved.");setCourseDraft({title:"",description:"",category:"Professional Development",contentUrl:"",durationMinutes:"",isPublished:true,sortOrder:0});setCourseOpen(false);await load(true);}catch(e){setError(e.message);}finally{setSaving(false);}}
  async function publishOpportunity(e){e.preventDefault();setSaving(true);try{await apiOps("adminPublishOpportunity","POST",opportunityDraft);flash("Assignment opportunity published.");setOpportunityDraft({assignmentId:"",status:"open",closesAt:"",notes:""});setOpportunityOpen(false);await load(true);}catch(e){setError(e.message);}finally{setSaving(false);}}

  if(!isSupabaseConfigured)return <PortalSetupNotice palette={palette}/>;
  if(loading)return <div className="min-h-[70vh] bg-[#f7f3ef] px-5 py-16"><div className="mx-auto max-w-4xl rounded-[2rem] bg-white p-16 text-center shadow-xl"><Loader2 className="mx-auto animate-spin text-[#721100]" size={32}/><h1 className="mt-5 text-2xl font-black">Preparing your MLS workspace</h1></div></div>;
  if(!workspace)return <div className="bg-[#f7f3ef] px-5 py-16"><Empty icon={AlertCircle} title="Portal unavailable" text={error||"Refresh and try again."}/></div>;

  const roleSections = portal==="admin" ? [["overview","Overview",LayoutDashboard],["clients","Clients",Building2],["interpreters","Interpreters",Users],["assignments","Assignments",CalendarDays],["documents","Documents",FileText],["training","Training",GraduationCap],["bids","Bids",ClipboardCheck],["feedback","Feedback",Star]] : portal==="client" ? [["overview","Overview",LayoutDashboard],["profile","Profile",UserRound],["documents","Documents",FileText],["request","Request",Plus],["assignments","Assignments",CalendarDays],["feedback","Feedback",Star]] : [["overview","Overview",LayoutDashboard],["profile","Profile",UserRound],["documents","Documents",FileText],["training","Training",GraduationCap],["opportunities","Opportunities",ClipboardCheck]];
  const portalOptions = [["admin","Admin",ShieldCheck],["client","Client",Building2],["interpreter","Interpreter",Users]].filter(([value])=>workspace.availablePortals?.includes(value));

  return <section className="relative min-h-screen overflow-hidden bg-[#f7f3ef]"><div className="pointer-events-none absolute inset-0 bg-[radial-gradient(circle_at_8%_5%,rgba(114,17,0,.09),transparent_25%),radial-gradient(circle_at_95%_10%,rgba(221,125,0,.13),transparent_28%)]"/><div className="relative mx-auto grid max-w-[100rem] gap-5 px-4 py-5 lg:grid-cols-[280px_minmax(0,1fr)] lg:px-6 lg:py-7"><aside className={join("fixed inset-y-0 left-0 z-50 w-[290px] overflow-y-auto bg-[#24130e] text-white shadow-2xl transition-transform lg:sticky lg:top-24 lg:h-[calc(100vh-7rem)] lg:w-auto lg:translate-x-0 lg:rounded-[2rem]",menuOpen?"translate-x-0":"-translate-x-full")}><div className="border-b border-white/10 p-5"><div className="flex items-center gap-3 rounded-2xl bg-white p-3"><img src={logo} alt="MLS" className="h-12 w-auto"/><div><p className="text-sm font-black text-[#464747]">Miqueas Language Solutions</p><p className="text-[10px] font-bold text-[#721100]">Portal Workspace</p></div></div><p className="mt-5 text-[10px] font-black uppercase tracking-[.18em] text-[#dd7d00]">Signed in as</p><p className="mt-1 truncate text-sm font-bold">{workspace.user.firstName||workspace.user.email}</p><p className="truncate text-xs text-white/50">{workspace.user.email}</p></div>{portalOptions.length>1&&<div className="border-b border-white/10 p-4"><p className="mb-2 text-[10px] font-black uppercase tracking-[.14em] text-white/40">Workspace</p>{portalOptions.map(([value,text,Icon])=><button key={value} onClick={()=>setPortal(value)} className={join("mb-2 flex w-full items-center gap-3 rounded-2xl px-4 py-3 text-sm font-black transition",portal===value?"bg-[#dd7d00] text-white shadow-lg":"text-white/70 hover:bg-white/10")}><Icon size={17}/><span className="flex-1 text-left">{text}</span><ArrowRight size={14}/></button>)}</div>}<nav className="space-y-1 p-4">{roleSections.map(([value,text,Icon])=><button key={value} onClick={()=>{setSection(value);setMenuOpen(false);}} className={join("flex w-full items-center gap-3 rounded-2xl px-4 py-3 text-sm font-black transition",section===value?"bg-white text-[#721100] shadow":"text-white/65 hover:bg-white/10 hover:text-white")}><Icon size={17}/><span className="flex-1 text-left">{text}</span></button>)}</nav><div className="border-t border-white/10 p-4"><button onClick={()=>load(true)} disabled={refreshing} className="mb-3 flex w-full items-center justify-center gap-2 rounded-2xl border border-white/10 bg-white/5 px-4 py-3 text-sm font-black text-white/75"><RefreshCcw size={16} className={refreshing?"animate-spin":""}/> Refresh</button><PortalSignOutButton/></div></aside>{menuOpen&&<button className="fixed inset-0 z-40 bg-black/30 lg:hidden" onClick={()=>setMenuOpen(false)}/>}<main className="min-w-0"><div className="mb-4 flex items-center justify-between lg:hidden"><button onClick={()=>setMenuOpen(true)} className="flex h-11 w-11 items-center justify-center rounded-2xl bg-[#24130e] text-white"><Menu size={20}/></button><p className="text-sm font-black text-[#721100]">{pretty(portal)} Portal</p></div>{error&&<div className="mb-5 flex gap-3 rounded-2xl border border-rose-200 bg-rose-50 p-4 text-sm text-rose-800"><AlertCircle size={18}/><span className="flex-1">{error}</span><button onClick={()=>setError("")}><X size={16}/></button></div>}{success&&<div className="mb-5 flex gap-3 rounded-2xl border border-emerald-200 bg-emerald-50 p-4 text-sm font-bold text-emerald-800"><CheckCircle2 size={18}/>{success}</div>}<AnimatePresence mode="wait"><motion.div key={`${portal}-${section}`} initial={{opacity:0,y:12}} animate={{opacity:1,y:0}} exit={{opacity:0,y:-8}} transition={{duration:.2}}>{portal==="admin"?<AdminContent section={section} workspace={workspace} operations={operations} setInviteOpen={setInviteOpen} setDocRequestOpen={setDocRequestOpen} setCourseOpen={setCourseOpen} setOpportunityOpen={setOpportunityOpen} updateAssignment={updateAssignment} apiOps={apiOps} reload={()=>load(true)} flash={flash} setError={setError}/>:portal==="client"?<ClientContent section={section} view={activeClient} operations={operations} setProfileOpen={setProfileOpen} setRequestOpen={setRequestOpen} busyDoc={busyDoc} upload={(t,f,id)=>upload("client",t,f,id)} open={(d)=>openDoc("client",d)} remove={(d)=>removeDoc("client",d)} feedbackDraft={feedbackDraft} setFeedbackDraft={setFeedbackDraft} submitFeedback={submitFeedback} saving={saving}/>:<InterpreterContent section={section} view={activeInterpreter} operations={operations} setProfileOpen={setProfileOpen} busyDoc={busyDoc} upload={(t,f,id)=>upload("interpreter",t,f,id)} open={(d)=>openDoc("interpreter",d)} remove={(d)=>removeDoc("interpreter",d)} progressCourse={progressCourse} submitBid={submitBid}/>}</motion.div></AnimatePresence></main></div>

  <Modal open={profileOpen} close={()=>setProfileOpen(false)} title={portal==="client"?"Client profile":"Interpreter profile"} wide><ProfileForm portal={portal} clientDraft={clientDraft} setClientDraft={setClientDraft} interpreterDraft={interpreterDraft} setInterpreterDraft={setInterpreterDraft} submit={saveProfile} saving={saving}/></Modal>
  <Modal open={requestOpen} close={()=>setRequestOpen(false)} title="Request an interpreter" wide><AssignmentForm draft={assignmentDraft} setDraft={setAssignmentDraft} submit={createAssignment} saving={saving}/></Modal>
  <Modal open={inviteOpen} close={()=>setInviteOpen(false)} title="Send portal invitation"><form onSubmit={inviteUser} className="space-y-4"><Field name="Role"><select className={INPUT} value={invite.role} onChange={(e)=>setInvite({...invite,role:e.target.value})}><option value="client">Client</option><option value="interpreter">Interpreter</option></select></Field><Field name="Email" required><input className={INPUT} type="email" required value={invite.email} onChange={(e)=>setInvite({...invite,email:e.target.value})}/></Field>{invite.role==="client"&&<Field name="Organization"><input className={INPUT} value={invite.organizationName} onChange={(e)=>setInvite({...invite,organizationName:e.target.value})}/></Field>}<button disabled={saving} className="inline-flex items-center gap-2 rounded-2xl bg-[#721100] px-5 py-3 text-sm font-black text-white"><Send size={16}/> Send invitation</button></form></Modal>
  <Modal open={docRequestOpen} close={()=>setDocRequestOpen(false)} title="Request a document"><DocumentRequestForm workspace={workspace} draft={docRequest} setDraft={setDocRequest} submit={createDocRequest} saving={saving}/></Modal>
  <Modal open={courseOpen} close={()=>setCourseOpen(false)} title="Add training course"><CourseForm draft={courseDraft} setDraft={setCourseDraft} submit={saveCourse} saving={saving}/></Modal>
  <Modal open={opportunityOpen} close={()=>setOpportunityOpen(false)} title="Publish assignment opportunity"><OpportunityForm assignments={workspace.admin?.assignments||[]} draft={opportunityDraft} setDraft={setOpportunityDraft} submit={publishOpportunity} saving={saving}/></Modal>
  </section>;
}

function Hero({ eyebrow,title,text,actions }){return <div className="overflow-hidden rounded-[2rem] bg-gradient-to-br from-[#721100] via-[#5b180b] to-[#2c1710] p-6 text-white shadow-2xl md:p-8"><div className="flex flex-col gap-6 lg:flex-row lg:items-end lg:justify-between"><div><p className="text-xs font-black uppercase tracking-[.18em] text-[#f6b34c]">{eyebrow}</p><h1 className="mt-3 text-3xl font-black tracking-tight md:text-5xl">{title}</h1><p className="mt-4 max-w-3xl text-sm leading-7 text-white/70">{text}</p></div><div className="flex flex-wrap gap-3">{actions}</div></div></div>;}

function AdminContent({section,workspace,operations,setInviteOpen,setDocRequestOpen,setCourseOpen,setOpportunityOpen,updateAssignment,apiOps,reload,flash,setError}){
  const clients=workspace.admin?.clients||[], interpreters=workspace.admin?.interpreters||[], assignments=workspace.admin?.assignments||[], requests=workspace.admin?.documentRequests||[];
  const [query,setQuery]=useState(""), [filters,setFilters]=useState({location:"",credentials:[],modalities:[],settings:[],experience:[],minRate:"",maxRate:""}), [showFilters,setShowFilters]=useState(false);
  const filtered=useMemo(()=>interpreters.filter((x)=>{const hay=[x.first_name,x.last_name,x.email,x.current_location,x.city,x.state,x.credentials,x.modalities,x.areas_of_experience,x.years_experience,x.onsite_rate,x.vri_rate].map(safe).join(" ").toLowerCase();const q=query.toLowerCase();const rate=Number(String(x.onsite_rate||x.vri_rate||"").match(/\d+(?:\.\d+)?/)?.[0]||NaN);return(!q||hay.includes(q))&&(!filters.location||hay.includes(filters.location.toLowerCase()))&&matches(x.credentials,filters.credentials)&&matches(x.modalities,filters.modalities)&&matches(x.areas_of_experience,filters.settings)&&matches(x.years_experience,filters.experience)&&(!filters.minRate||(!Number.isNaN(rate)&&rate>=Number(filters.minRate)))&&(!filters.maxRate||(!Number.isNaN(rate)&&rate<=Number(filters.maxRate)));}),[interpreters,query,filters]);
  const toggle=(key,value)=>setFilters((f)=>({...f,[key]:f[key].includes(value)?f[key].filter((x)=>x!==value):[...f[key],value]}));
  if(section==="overview")return <div className="space-y-6"><Hero eyebrow="MLS operations center" title="Everything MLS needs, in one place." text="Manage people, requests, files, training, bids, and feedback without leaving the admin workspace." actions={<><button onClick={()=>setInviteOpen(true)} className="rounded-2xl bg-[#dd7d00] px-5 py-3 text-sm font-black">Invite user</button><button onClick={()=>setDocRequestOpen(true)} className="rounded-2xl border border-white/15 bg-white/10 px-5 py-3 text-sm font-black">Request document</button></>}/><div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-5"><Metric icon={Building2} name="Clients" value={clients.length} note="Active profiles"/><Metric icon={Users} name="Interpreters" value={interpreters.length} note="Roster profiles" color={BRAND.gold}/><Metric icon={CalendarDays} name="Pending" value={assignments.filter((x)=>x.status==="pending_confirmation").length} note="Awaiting confirmation"/><Metric icon={ClipboardCheck} name="Open bids" value={(operations?.admin?.opportunities||[]).filter((x)=>x.status==="open").length} note="Published assignments" color="#15803d"/><Metric icon={Star} name="Feedback" value={(operations?.admin?.feedback||[]).length} note="Client submissions" color="#c2410c"/></div><div className="grid gap-5 xl:grid-cols-2"><Card><SectionTitle eyebrow="Attention" title="Document requests" text="Outstanding files across both portals."/><div className="mt-5 space-y-3">{requests.slice(0,6).map((x)=><div key={x.id} className="flex items-center gap-3 rounded-2xl bg-slate-50 p-4"><FileText size={18} className="text-[#721100]"/><div className="min-w-0 flex-1"><p className="truncate text-sm font-black">{x.title}</p><p className="text-xs text-slate-400">{pretty(x.audience_type)} · {pretty(x.status)}</p></div></div>)}{!requests.length&&<Empty title="No document requests" text="Create one when a file is needed."/>}</div></Card><Card><SectionTitle eyebrow="Recent" title="Assignment pipeline" text="Latest client requests and current status."/><div className="mt-5 space-y-3">{assignments.slice(0,6).map((x)=><div key={x.id} className="rounded-2xl bg-slate-50 p-4"><div className="flex items-center justify-between gap-3"><p className="font-black">{x.clients?.organization_name||x.clients?.email}</p><Badge value={x.status}/></div><p className="mt-1 text-xs text-slate-500">{x.service_type} · {formatDate(x.start_at)}</p></div>)}{!assignments.length&&<Empty title="No assignments yet" text="Client requests will appear here."/>}</div></Card></div></div>;
  if(section==="clients")return <DirectoryPanel title="Clients" records={clients} type="client"/>;
  if(section==="interpreters")return <div className="space-y-5"><Card><SectionTitle eyebrow="Directory" title="Interpreters" text={`${filtered.length} of ${interpreters.length} profiles`} action={<button onClick={()=>setShowFilters(!showFilters)} className="inline-flex items-center gap-2 rounded-2xl border border-slate-200 px-4 py-3 text-sm font-black text-[#721100]"><Filter size={16}/> Filters <ChevronDown size={15}/></button>}/><div className="mt-5 flex items-center gap-3 rounded-2xl border border-slate-200 bg-slate-50 px-4 py-3"><Search size={18} className="text-[#dd7d00]"/><input value={query} onChange={(e)=>setQuery(e.target.value)} placeholder="Search name, location, credentials, settings, or rate" className="w-full bg-transparent text-sm font-bold outline-none"/></div><AnimatePresence>{showFilters&&<motion.div initial={{height:0,opacity:0}} animate={{height:"auto",opacity:1}} exit={{height:0,opacity:0}} className="overflow-hidden"><div className="mt-4 grid gap-4 md:grid-cols-2 xl:grid-cols-4"><FilterGroup label="Credentials" options={CREDENTIAL_OPTIONS} values={filters.credentials} toggle={(v)=>toggle("credentials",v)}/><FilterGroup label="Modalities" options={MODALITY_OPTIONS} values={filters.modalities} toggle={(v)=>toggle("modalities",v)}/><FilterGroup label="Settings" options={SETTING_OPTIONS} values={filters.settings} toggle={(v)=>toggle("settings",v)}/><FilterGroup label="Experience" options={EXPERIENCE_OPTIONS} values={filters.experience} toggle={(v)=>toggle("experience",v)}/></div><div className="mt-4 grid gap-3 md:grid-cols-3"><input className={INPUT} placeholder="Location" value={filters.location} onChange={(e)=>setFilters({...filters,location:e.target.value})}/><input className={INPUT} type="number" placeholder="Minimum rate" value={filters.minRate} onChange={(e)=>setFilters({...filters,minRate:e.target.value})}/><input className={INPUT} type="number" placeholder="Maximum rate" value={filters.maxRate} onChange={(e)=>setFilters({...filters,maxRate:e.target.value})}/></div></motion.div>}</AnimatePresence></Card><div className="grid gap-4 lg:grid-cols-2 xl:grid-cols-3">{filtered.map((x)=><Card key={x.id}><div className="flex items-start gap-3"><span className="flex h-12 w-12 items-center justify-center rounded-2xl bg-[#721100]/10 font-black text-[#721100]">{(x.first_name||x.email||"?")[0]}</span><div className="min-w-0 flex-1"><h3 className="truncate text-lg font-black">{`${x.first_name||""} ${x.last_name||""}`.trim()||x.email}</h3><p className="text-xs text-slate-500">{x.current_location||[x.city,x.state].filter(Boolean).join(", ")||"Location not provided"}</p></div><Badge value={x.roster_status}/></div><div className="mt-4 space-y-2 text-sm text-slate-600"><p><b>Credentials:</b> {x.credentials||"—"}</p><p><b>Modalities:</b> {x.modalities||"—"}</p><p><b>Settings:</b> {x.areas_of_experience||"—"}</p><p><b>Experience:</b> {x.years_experience||"—"}</p><p><b>Rates:</b> {x.onsite_rate||"—"} on-site · {x.vri_rate||"—"} VRI</p></div></Card>)}{!filtered.length&&<Empty title="No interpreters match" text="Adjust the filters or search terms."/>}</div></div>;
  if(section==="assignments")return <Card><SectionTitle eyebrow="Operations" title="Assignments" text="Update confirmation and payment states from one table." action={<button onClick={()=>setOpportunityOpen(true)} className="rounded-2xl bg-[#721100] px-4 py-3 text-sm font-black text-white">Publish opportunity</button>}/><div className="mt-5 overflow-x-auto"><table className="min-w-full text-left text-sm"><thead><tr className="text-[11px] uppercase tracking-[.1em] text-slate-400"><th className="p-3">Client</th><th className="p-3">Assignment</th><th className="p-3">Date</th><th className="p-3">Status</th><th className="p-3">Payment</th></tr></thead><tbody>{assignments.map((x)=><tr key={x.id} className="border-t border-slate-100"><td className="p-3 font-black">{x.clients?.organization_name||x.clients?.email}</td><td className="p-3">{x.service_type}<p className="text-xs text-slate-400">{x.delivery_mode}</p></td><td className="p-3 text-xs font-bold">{formatDate(x.start_at)}</td><td className="p-3"><select className="rounded-xl border border-slate-200 p-2 text-xs font-bold" value={x.status} onChange={(e)=>updateAssignment(x,{status:e.target.value})}><option value="pending_confirmation">Pending</option><option value="confirmed">Confirmed</option><option value="completed">Completed</option><option value="cancelled">Cancelled</option></select></td><td className="p-3"><select className="rounded-xl border border-slate-200 p-2 text-xs font-bold" value={x.payment_status} onChange={(e)=>updateAssignment(x,{paymentStatus:e.target.value})}><option value="not_invoiced">Not invoiced</option><option value="pending_payment">Pending payment</option><option value="paid">Paid</option><option value="void">Void</option></select></td></tr>)}</tbody></table>{!assignments.length&&<Empty title="No assignments" text="Client requests will appear here."/>}</div></Card>;
  if(section==="documents")return <Card><SectionTitle eyebrow="Documents" title="Document requests" text="Request files from clients and interpreters without leaving the portal." action={<button onClick={()=>setDocRequestOpen(true)} className="rounded-2xl bg-[#721100] px-4 py-3 text-sm font-black text-white">New request</button>}/><div className="mt-5 grid gap-3 lg:grid-cols-2">{requests.map((x)=><div key={x.id} className="rounded-2xl bg-slate-50 p-4"><div className="flex justify-between gap-3"><p className="font-black">{x.title}</p><Badge value={x.status}/></div><p className="mt-1 text-xs text-slate-500">{pretty(x.audience_type)} · Due {x.due_date||"not set"}</p><p className="mt-2 text-sm text-slate-600">{x.instructions}</p></div>)}{!requests.length&&<Empty title="No document requests" text="Create one when a required file is missing."/>}</div></Card>;
  if(section==="training")return <Card><SectionTitle eyebrow="Learning" title="Training center" text="Publish MLS onboarding and professional development content." action={<button onClick={()=>setCourseOpen(true)} className="rounded-2xl bg-[#721100] px-4 py-3 text-sm font-black text-white">Add course</button>}/><div className="mt-5 grid gap-4 lg:grid-cols-2">{(operations?.admin?.courses||[]).map((x)=><div key={x.id} className="rounded-2xl bg-slate-50 p-5"><div className="flex justify-between gap-3"><div><p className="text-xs font-black uppercase text-[#dd7d00]">{x.category}</p><h3 className="mt-1 text-lg font-black">{x.title}</h3></div><Badge value={x.is_published?"published":"draft"}/></div><p className="mt-3 text-sm text-slate-600">{x.description}</p><p className="mt-3 text-xs text-slate-400">{x.duration_minutes?`${x.duration_minutes} minutes`:"Self-paced"}</p></div>)}{!(operations?.admin?.courses||[]).length&&<Empty title="No courses" text="Add the first training course."/>}</div></Card>;
  if(section==="bids")return <Card><SectionTitle eyebrow="Staffing" title="Interpreter bids" text="Review interest in open assignments and move candidates through selection."/><div className="mt-5 space-y-3">{(operations?.admin?.bids||[]).map((x)=><div key={x.id} className="rounded-2xl bg-slate-50 p-4"><div className="flex flex-col gap-3 md:flex-row md:items-center md:justify-between"><div><p className="font-black">{`${x.interpreters?.first_name||""} ${x.interpreters?.last_name||""}`.trim()||x.interpreters?.email}</p><p className="text-xs text-slate-500">{x.assignment_opportunities?.assignments?.service_type} · {formatDate(x.assignment_opportunities?.assignments?.start_at)}</p><p className="mt-2 text-sm text-slate-600">{x.message||"No note"} {x.bid_rate&&`· $${x.bid_rate}/hr`}</p></div><select className="rounded-xl border border-slate-200 p-2 text-xs font-bold" value={x.status} onChange={async(e)=>{try{await apiOps("adminUpdateBid","POST",{bidId:x.id,status:e.target.value});flash("Bid updated.");await reload();}catch(err){setError(err.message);}}}><option value="submitted">Submitted</option><option value="shortlisted">Shortlisted</option><option value="accepted">Accepted</option><option value="declined">Declined</option></select></div></div>)}{!(operations?.admin?.bids||[]).length&&<Empty title="No bids yet" text="Interpreter bids will appear here."/>}</div></Card>;
  if(section==="feedback")return <Card><SectionTitle eyebrow="Quality" title="Client feedback" text="Review ratings, comments, and follow-up requests."/><div className="mt-5 grid gap-4 lg:grid-cols-2">{(operations?.admin?.feedback||[]).map((x)=><div key={x.id} className="rounded-2xl bg-slate-50 p-5"><div className="flex justify-between gap-3"><p className="font-black">{x.clients?.organization_name||x.clients?.email}</p><span className="font-black text-[#dd7d00]">{"★".repeat(x.rating)}</span></div><p className="mt-2 text-xs text-slate-500">{x.assignments?.service_type||"General feedback"}</p><p className="mt-3 text-sm text-slate-700">{x.comments||"No written comments."}</p>{x.follow_up_requested&&<p className="mt-3 text-xs font-black text-[#721100]">Follow-up requested</p>}</div>)}{!(operations?.admin?.feedback||[]).length&&<Empty title="No feedback yet" text="Client feedback will appear here."/>}</div></Card>;
  return null;
}

function FilterGroup({label,options,values,toggle}){return <div className="rounded-2xl border border-slate-200 bg-white p-4"><p className="text-xs font-black uppercase tracking-[.1em] text-[#dd7d00]">{label}</p><div className="mt-3 max-h-44 space-y-2 overflow-y-auto">{options.map((o)=><label key={o} className="flex gap-2 text-sm text-slate-700"><input type="checkbox" checked={values.includes(o)} onChange={()=>toggle(o)}/><span>{o}</span></label>)}</div></div>;}
function DirectoryPanel({title,records,type}){return <Card><SectionTitle eyebrow="Directory" title={title} text={`${records.length} profiles`}/><div className="mt-5 grid gap-3 lg:grid-cols-2">{records.map((x)=>{const main=type==="client"?x.organization_name||x.email:`${x.first_name||""} ${x.last_name||""}`.trim()||x.email;return <div key={x.id} className="flex items-center gap-3 rounded-2xl bg-slate-50 p-4"><span className="flex h-11 w-11 items-center justify-center rounded-xl bg-[#721100]/10 font-black text-[#721100]">{main?.[0]}</span><div className="min-w-0 flex-1"><p className="truncate text-sm font-black">{main}</p><p className="truncate text-xs text-slate-400">{x.email}</p></div><Badge value={x.account_status||x.roster_status||"active"}/></div>;})}{!records.length&&<Empty title={`No ${type}s yet`} text="Use the invitation tool to add the first profile."/>}</div></Card>;}

function ClientContent({section,view,operations,setProfileOpen,setRequestOpen,busyDoc,upload,open,remove,feedbackDraft,setFeedbackDraft,submitFeedback,saving}){
  if(!view?.profile)return <Empty icon={Building2} title="Client profile unavailable" text="Complete account setup to begin."/>;
  const p=view.profile, assignments=view.assignments||[], docs=Object.fromEntries((view.documents||[]).map((x)=>[x.document_type,x])), requests=Object.fromEntries((view.documentRequests||[]).map((x)=>[x.document_type,x]));
  if(section==="overview")return <div className="space-y-6"><Hero eyebrow="Client workspace" title={`Welcome, ${p.organization_name||p.primary_contact_name||"MLS client"}.`} text="Request communication access, upload preparation materials, track assignments, and share feedback from one place." actions={<><button onClick={()=>setRequestOpen(true)} className="rounded-2xl bg-[#dd7d00] px-5 py-3 text-sm font-black">Request interpreter</button><button onClick={()=>setProfileOpen(true)} className="rounded-2xl border border-white/15 bg-white/10 px-5 py-3 text-sm font-black">Edit profile</button></>}/><div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4"><Metric icon={CalendarDays} name="Pending" value={assignments.filter((x)=>x.status==="pending_confirmation").length} note="Awaiting confirmation"/><Metric icon={CheckCircle2} name="Confirmed" value={assignments.filter((x)=>x.status==="confirmed").length} note="Upcoming work" color="#15803d"/><Metric icon={CircleDollarSign} name="Payment due" value={assignments.filter((x)=>x.payment_status==="pending_payment").length} note="Invoices pending" color="#c2410c"/><Metric icon={FileCheck2} name="Documents" value={(view.documents||[]).length} note="Secure files" color={BRAND.gold}/></div></div>;
  if(section==="profile")return <Card><SectionTitle eyebrow="Profile" title="Organization and billing" text="Keep contact and billing details current." action={<button onClick={()=>setProfileOpen(true)} className="rounded-2xl bg-[#721100] px-4 py-3 text-sm font-black text-white">Edit profile</button>}/><div className="mt-5 grid gap-4 sm:grid-cols-2 lg:grid-cols-3">{[["Organization",p.organization_name],["Primary contact",p.primary_contact_name],["Phone",p.phone],["Billing email",p.billing_email],["Industry",p.industry],["Default service",p.default_service_type]].map(([n,v])=><div key={n} className="rounded-2xl bg-slate-50 p-4"><p className="text-[10px] font-black uppercase tracking-[.1em] text-slate-400">{n}</p><p className="mt-2 text-sm font-bold text-slate-700">{v||"Not provided"}</p></div>)}</div></Card>;
  if(section==="documents")return <Card><SectionTitle eyebrow="Documents" title="Secure upload center" text="Upload requested files and preparation materials."/><div className="mt-5 grid gap-4 lg:grid-cols-2">{CLIENT_DOCS.map(([type,title])=><DocumentCard key={type} type={type} title={title} document={docs[type]} request={requests[type]} busy={busyDoc} upload={upload} open={open} remove={remove}/>)}</div></Card>;
  if(section==="request")return <Card><SectionTitle eyebrow="Request tool" title="Need an interpreter?" text="Submit a detailed request so MLS can confirm the right access team quickly." action={<button onClick={()=>setRequestOpen(true)} className="rounded-2xl bg-[#721100] px-5 py-3 text-sm font-black text-white">Start request</button>}/><Empty icon={Plus} title="Create a new request" text="Dates, modality, location, participant details, and preparation notes are collected in one guided form."/></Card>;
  if(section==="assignments")return <Card><SectionTitle eyebrow="History" title="Assignments" text="Track every request from pending confirmation through payment."/><div className="mt-5 space-y-3">{assignments.map((x)=><div key={x.id} className="rounded-2xl bg-slate-50 p-5"><div className="flex flex-wrap items-center gap-2"><p className="font-black">{x.service_type}</p><Badge value={x.status}/><Badge value={x.payment_status}/></div><p className="mt-2 text-sm font-bold text-slate-600">{formatDate(x.start_at)} · {x.delivery_mode}</p><p className="mt-1 text-xs text-slate-400">{x.location_name||x.meeting_link||x.description}</p></div>)}{!assignments.length&&<Empty title="No assignments yet" text="Submit your first request when communication access is needed."/>}</div></Card>;
  if(section==="feedback")return <div className="grid gap-5 xl:grid-cols-2"><Card><SectionTitle eyebrow="Feedback" title="Tell us how it went" text="Your feedback helps MLS improve service quality and interpreter matching."/><form onSubmit={submitFeedback} className="mt-5 space-y-4"><Field name="Assignment"><select className={INPUT} value={feedbackDraft.assignmentId} onChange={(e)=>setFeedbackDraft({...feedbackDraft,assignmentId:e.target.value})}><option value="">General feedback</option>{assignments.map((x)=><option key={x.id} value={x.id}>{x.service_type} · {formatDate(x.start_at)}</option>)}</select></Field><Field name="Rating"><select className={INPUT} value={feedbackDraft.rating} onChange={(e)=>setFeedbackDraft({...feedbackDraft,rating:Number(e.target.value)})}>{[5,4,3,2,1].map((n)=><option key={n} value={n}>{n} star{n!==1?"s":""}</option>)}</select></Field><Field name="Comments"><textarea className={join(INPUT,"min-h-32")} value={feedbackDraft.comments} onChange={(e)=>setFeedbackDraft({...feedbackDraft,comments:e.target.value})}/></Field><label className="flex items-center gap-2 text-sm font-bold text-slate-600"><input type="checkbox" checked={feedbackDraft.followUpRequested} onChange={(e)=>setFeedbackDraft({...feedbackDraft,followUpRequested:e.target.checked})}/> I would like MLS to follow up</label><button disabled={saving} className="rounded-2xl bg-[#721100] px-5 py-3 text-sm font-black text-white">Submit feedback</button></form></Card><Card><SectionTitle eyebrow="History" title="Previous feedback" text="A record of what you have shared."/><div className="mt-5 space-y-3">{(operations?.feedback||[]).map((x)=><div key={x.id} className="rounded-2xl bg-slate-50 p-4"><p className="font-black text-[#dd7d00]">{"★".repeat(x.rating)}</p><p className="mt-2 text-sm text-slate-700">{x.comments||"No comments."}</p></div>)}{!(operations?.feedback||[]).length&&<Empty title="No feedback submitted" text="Completed submissions will appear here."/>}</div></Card></div>;
  return null;
}

function InterpreterContent({section,view,operations,setProfileOpen,busyDoc,upload,open,remove,progressCourse,submitBid}){
  if(!view?.profile)return <Empty icon={Users} title="Interpreter profile unavailable" text="Complete your profile to access assignments and training."/>;
  const p=view.profile, docs=Object.fromEntries((view.documents||[]).map((x)=>[x.document_type,x])), requests=Object.fromEntries((view.documentRequests||[]).map((x)=>[x.document_type,x]));
  const complete=Math.round(([p.phone,p.current_location,p.credentials,p.modalities,p.areas_of_experience,p.assignment_type_preference].filter(Boolean).length/6)*100);
  if(section==="overview")return <div className="space-y-6"><Hero eyebrow="Interpreter workspace" title={`${p.first_name||"Interpreter"}, stay assignment-ready.`} text="Keep your profile current, complete MLS training, manage requested documents, and bid on assignments that fit your skills." actions={<button onClick={()=>setProfileOpen(true)} className="rounded-2xl bg-[#dd7d00] px-5 py-3 text-sm font-black">Edit profile</button>}/><div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4"><Metric icon={UserRound} name="Profile" value={`${complete}%`} note="Core details complete"/><Metric icon={FileCheck2} name="Documents" value={(view.documents||[]).length} note="Secure files" color="#15803d"/><Metric icon={GraduationCap} name="Training" value={(operations?.training||[]).filter((x)=>x.progress?.status==="completed").length} note="Courses completed" color={BRAND.gold}/><Metric icon={ClipboardCheck} name="Opportunities" value={(operations?.opportunities||[]).length} note="Open for bidding" color="#c2410c"/></div></div>;
  if(section==="profile")return <Card><SectionTitle eyebrow="Profile" title="Assignment-matching profile" text="MLS uses these details to match skill, modality, location, and setting appropriately." action={<button onClick={()=>setProfileOpen(true)} className="rounded-2xl bg-[#721100] px-4 py-3 text-sm font-black text-white">Edit profile</button>}/><div className="mt-5 grid gap-4 sm:grid-cols-2 lg:grid-cols-4">{[["Credentials",p.credentials],["Location",p.current_location],["Modalities",p.modalities],["Experience",p.years_experience],["Settings",p.areas_of_experience],["Preference",p.assignment_type_preference],["Travel",p.willing_to_travel],["PLI",p.professional_liability_insurance]].map(([n,v])=><div key={n} className="rounded-2xl bg-slate-50 p-4"><p className="text-[10px] font-black uppercase tracking-[.1em] text-slate-400">{n}</p><p className="mt-2 text-sm font-bold text-slate-700">{v||"Not provided"}</p></div>)}</div></Card>;
  if(section==="documents")return <Card><SectionTitle eyebrow="Documents" title="Requested onboarding files" text="Upload only what MLS requests and replace outdated versions anytime."/><div className="mt-5 grid gap-4 lg:grid-cols-2">{INTERPRETER_DOCS.map(([type,title])=><DocumentCard key={type} type={type} title={title} document={docs[type]} request={requests[type]} busy={busyDoc} upload={upload} open={open} remove={remove}/>)}</div></Card>;
  if(section==="training")return <Card><SectionTitle eyebrow="Learning" title="Training center" text="Complete MLS onboarding and professional development at your pace."/><div className="mt-5 grid gap-4 lg:grid-cols-2">{(operations?.training||[]).map((x)=>{const percent=x.progress?.progress_percent||0;return <div key={x.id} className="rounded-2xl bg-slate-50 p-5"><p className="text-xs font-black uppercase text-[#dd7d00]">{x.category}</p><h3 className="mt-1 text-lg font-black">{x.title}</h3><p className="mt-2 text-sm text-slate-600">{x.description}</p><div className="mt-4 h-2 overflow-hidden rounded-full bg-slate-200"><div className="h-full rounded-full bg-[#721100] transition-all" style={{width:`${percent}%`}}/></div><div className="mt-3 flex items-center justify-between"><span className="text-xs font-bold text-slate-500">{percent}% complete</span><div className="flex gap-2">{x.content_url&&<a href={x.content_url} target="_blank" rel="noreferrer" className="rounded-xl border border-slate-200 px-3 py-2 text-xs font-black">Open</a>}<button onClick={()=>progressCourse(x,percent===100?0:100)} className="rounded-xl bg-[#721100] px-3 py-2 text-xs font-black text-white">{percent===100?"Reset":"Mark complete"}</button></div></div></div>;})}{!(operations?.training||[]).length&&<Empty title="No training available" text="Published courses will appear here."/>}</div></Card>;
  if(section==="opportunities")return <Card><SectionTitle eyebrow="Assignments" title="Recommended opportunities" text="Bid only on assignments that fit your qualifications, location, availability, and rate expectations."/><div className="mt-5 space-y-4">{(operations?.opportunities||[]).map((x)=>{const a=x.assignments||{};const existing=(operations?.bids||[]).find((b)=>b.opportunity_id===x.id);return <div key={x.id} className="rounded-2xl border border-slate-200 bg-white p-5"><div className="flex flex-col gap-4 md:flex-row md:items-start md:justify-between"><div><div className="flex flex-wrap items-center gap-2"><h3 className="text-lg font-black">{a.service_type}</h3><Badge value={x.status}/>{existing&&<Badge value={existing.status}/>}</div><p className="mt-2 text-sm font-bold text-slate-600">{formatDate(a.start_at)} · {a.delivery_mode}</p><p className="mt-1 text-xs text-slate-400">{a.location_name||[a.city,a.state].filter(Boolean).join(", ")||"Remote"}</p><p className="mt-3 text-sm text-slate-600">{a.specialty} · {a.language_preferences}</p>{x.notes&&<p className="mt-2 text-sm text-slate-500">{x.notes}</p>}</div><button disabled={Boolean(existing)} onClick={()=>submitBid(x)} className="rounded-2xl bg-[#721100] px-5 py-3 text-sm font-black text-white disabled:bg-slate-300">{existing?"Bid submitted":"Bid for assignment"}</button></div></div>;})}{!(operations?.opportunities||[]).length&&<Empty title="No open opportunities" text="Recommended assignments will appear here when MLS publishes them."/>}</div></Card>;
  return null;
}

function ProfileForm({portal,clientDraft,setClientDraft,interpreterDraft,setInterpreterDraft,submit,saving}){const d=portal==="client"?clientDraft:interpreterDraft;const set=(name)=>(e)=>(portal==="client"?setClientDraft({...d,[name]:e.target.value}):setInterpreterDraft({...d,[name]:e.target.value}));return <form onSubmit={submit} className="space-y-6"><div className="grid gap-4 md:grid-cols-2">{portal==="client"?<><Field name="Organization" required><input className={INPUT} required value={d.organization_name} onChange={set("organization_name")}/></Field><Field name="Primary contact" required><input className={INPUT} required value={d.primary_contact_name} onChange={set("primary_contact_name")}/></Field><Field name="Phone" required><input className={INPUT} required value={d.phone} onChange={set("phone")}/></Field><Field name="Billing email" required><input className={INPUT} type="email" required value={d.billing_email} onChange={set("billing_email")}/></Field><Field name="Industry"><input className={INPUT} value={d.industry} onChange={set("industry")}/></Field><Field name="Preferred contact"><select className={INPUT} value={d.preferred_contact_method} onChange={set("preferred_contact_method")}><option>Email</option><option>Phone</option><option>Text</option></select></Field><Field name="Address" className="md:col-span-2"><input className={INPUT} value={d.address_line_1} onChange={set("address_line_1")}/></Field><Field name="City"><input className={INPUT} value={d.city} onChange={set("city")}/></Field><Field name="State"><input className={INPUT} value={d.state} onChange={set("state")}/></Field></>:<><Field name="First name"><input className={INPUT} value={d.first_name} onChange={set("first_name")}/></Field><Field name="Last name"><input className={INPUT} value={d.last_name} onChange={set("last_name")}/></Field><Field name="Phone"><input className={INPUT} value={d.phone} onChange={set("phone")}/></Field><Field name="Location"><input className={INPUT} value={d.current_location} onChange={set("current_location")}/></Field><Field name="Credentials"><input className={INPUT} value={d.credentials} onChange={set("credentials")}/></Field><Field name="Modalities"><input className={INPUT} value={d.modalities} onChange={set("modalities")}/></Field><Field name="Settings" className="md:col-span-2"><input className={INPUT} value={d.areas_of_experience} onChange={set("areas_of_experience")}/></Field><Field name="Experience"><select className={INPUT} value={d.years_experience} onChange={set("years_experience")}><option value="">Choose</option>{EXPERIENCE_OPTIONS.map((x)=><option key={x}>{x}</option>)}</select></Field><Field name="Assignment preference"><select className={INPUT} value={d.assignment_type_preference} onChange={set("assignment_type_preference")}><option value="">Choose</option><option>In-Person</option><option>VRI</option><option>Both</option></select></Field><Field name="On-site rate"><input className={INPUT} value={d.onsite_rate} onChange={set("onsite_rate")}/></Field><Field name="VRI rate"><input className={INPUT} value={d.vri_rate} onChange={set("vri_rate")}/></Field></>}</div><button disabled={saving} className="inline-flex items-center gap-2 rounded-2xl bg-[#721100] px-5 py-3 text-sm font-black text-white">{saving?<Loader2 className="animate-spin" size={16}/>:<Save size={16}/>} Save profile</button></form>;}
function AssignmentForm({draft,setDraft,submit,saving}){const set=(n)=>(e)=>setDraft({...draft,[n]:e.target.type==="checkbox"?e.target.checked:e.target.value});return <form onSubmit={submit} className="space-y-5"><div className="grid gap-4 md:grid-cols-2"><Field name="Service" required><select className={INPUT} value={draft.service_type} onChange={set("service_type")}><option>ASL/English Interpreting</option><option>Certified Deaf Interpreter Team</option><option>DeafBlind / ProTactile Access</option><option>ASL Video Translation</option></select></Field><Field name="Delivery mode" required><select className={INPUT} value={draft.delivery_mode} onChange={set("delivery_mode")}><option>On-site</option><option>VRI</option><option>Hybrid</option></select></Field><Field name="Start" required><input className={INPUT} type="datetime-local" required value={draft.start_at} onChange={set("start_at")}/></Field><Field name="End"><input className={INPUT} type="datetime-local" value={draft.end_at} onChange={set("end_at")}/></Field><Field name="Location"><input className={INPUT} value={draft.location_name} onChange={set("location_name")}/></Field><Field name="Meeting link"><input className={INPUT} value={draft.meeting_link} onChange={set("meeting_link")}/></Field><Field name="Specialty"><input className={INPUT} value={draft.specialty} onChange={set("specialty")}/></Field><Field name="Language preferences"><input className={INPUT} value={draft.language_preferences} onChange={set("language_preferences")}/></Field><Field name="Description" className="md:col-span-2"><textarea className={join(INPUT,"min-h-28")} value={draft.description} onChange={set("description")}/></Field></div><div className="flex flex-wrap gap-4"><label className="flex items-center gap-2 text-sm font-bold"><input type="checkbox" checked={draft.team_requested} onChange={set("team_requested")}/> Team requested</label><label className="flex items-center gap-2 text-sm font-bold"><input type="checkbox" checked={draft.cdi_requested} onChange={set("cdi_requested")}/> CDI requested</label></div><button disabled={saving} className="rounded-2xl bg-[#721100] px-5 py-3 text-sm font-black text-white">Submit request</button></form>;}
function DocumentRequestForm({workspace,draft,setDraft,submit,saving}){const list=draft.audienceType==="client"?workspace.admin?.clients||[]:workspace.admin?.interpreters||[];return <form onSubmit={submit} className="space-y-4"><Field name="Audience"><select className={INPUT} value={draft.audienceType} onChange={(e)=>setDraft({...draft,audienceType:e.target.value,ownerId:"",documentType:e.target.value==="client"?"service_agreement":"resume"})}><option value="client">Client</option><option value="interpreter">Interpreter</option></select></Field><Field name="Recipient" required><select className={INPUT} required value={draft.ownerId} onChange={(e)=>setDraft({...draft,ownerId:e.target.value})}><option value="">Choose</option>{list.map((x)=><option key={x.id} value={x.id}>{draft.audienceType==="client"?x.organization_name||x.email:`${x.first_name||""} ${x.last_name||""}`.trim()||x.email}</option>)}</select></Field><Field name="Document type"><select className={INPUT} value={draft.documentType} onChange={(e)=>setDraft({...draft,documentType:e.target.value})}>{(draft.audienceType==="client"?CLIENT_DOCS:INTERPRETER_DOCS).map(([v,n])=><option key={v} value={v}>{n}</option>)}</select></Field><Field name="Title" required><input className={INPUT} required value={draft.title} onChange={(e)=>setDraft({...draft,title:e.target.value})}/></Field><Field name="Instructions"><textarea className={join(INPUT,"min-h-24")} value={draft.instructions} onChange={(e)=>setDraft({...draft,instructions:e.target.value})}/></Field><Field name="Due date"><input className={INPUT} type="date" value={draft.dueDate} onChange={(e)=>setDraft({...draft,dueDate:e.target.value})}/></Field><button disabled={saving} className="rounded-2xl bg-[#721100] px-5 py-3 text-sm font-black text-white">Create request</button></form>;}
function CourseForm({draft,setDraft,submit,saving}){return <form onSubmit={submit} className="space-y-4"><Field name="Course title" required><input className={INPUT} required value={draft.title} onChange={(e)=>setDraft({...draft,title:e.target.value})}/></Field><Field name="Category"><input className={INPUT} value={draft.category} onChange={(e)=>setDraft({...draft,category:e.target.value})}/></Field><Field name="Description"><textarea className={join(INPUT,"min-h-28")} value={draft.description} onChange={(e)=>setDraft({...draft,description:e.target.value})}/></Field><Field name="Content URL"><input className={INPUT} type="url" value={draft.contentUrl} onChange={(e)=>setDraft({...draft,contentUrl:e.target.value})}/></Field><Field name="Duration (minutes)"><input className={INPUT} type="number" value={draft.durationMinutes} onChange={(e)=>setDraft({...draft,durationMinutes:e.target.value})}/></Field><button disabled={saving} className="rounded-2xl bg-[#721100] px-5 py-3 text-sm font-black text-white">Save course</button></form>;}
function OpportunityForm({assignments,draft,setDraft,submit,saving}){return <form onSubmit={submit} className="space-y-4"><Field name="Assignment" required><select className={INPUT} required value={draft.assignmentId} onChange={(e)=>setDraft({...draft,assignmentId:e.target.value})}><option value="">Choose</option>{assignments.map((x)=><option key={x.id} value={x.id}>{x.clients?.organization_name||x.clients?.email} · {x.service_type} · {formatDate(x.start_at)}</option>)}</select></Field><Field name="Closes at"><input className={INPUT} type="datetime-local" value={draft.closesAt} onChange={(e)=>setDraft({...draft,closesAt:e.target.value})}/></Field><Field name="Notes"><textarea className={join(INPUT,"min-h-24")} value={draft.notes} onChange={(e)=>setDraft({...draft,notes:e.target.value})}/></Field><button disabled={saving} className="rounded-2xl bg-[#721100] px-5 py-3 text-sm font-black text-white">Publish opportunity</button></form>;}
